#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,P,Q; scanf("%lld %lld %lld %lld", &A,&B,&P,&Q);
        if(P % A != 0 || Q % B != 0){
            printf("NO\n");
            continue;
        }
        long long a = P / A;
        long long b = Q / B;
        if(llabs(a - b) <= 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

