#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); P = int(next(it)); Q = int(next(it))
        if P % A != 0 or Q % B != 0:
            out.append("NO")
            continue
        a = P // A
        b = Q // B
        out.append("YES" if abs(a - b) <= 1 else "NO")
    sys.stdout.write("\n".join(out))
if __name__ == "__main__":
    solve()

